// ── Latest snapshot per city (for dashboard widgets) ──────────────────────────
export const LATEST_BY_CITY = (() => {
  const map = {};
  QUARTERLY_INDEX.forEach(row => {
    const key = `${row.city}::${row.type}`;
    if (!map[key] || row.period > map[key].period) map[key] = row;
  });
  return Object.values(map);
})();

// ── Residential index only (for trend charts) ─────────────────────────────────
export const RESIDENTIAL_TREND = QUARTERLY_INDEX.filter(r => r.type === 'سكني');

// ── RESURGO Composite Index (weighted average across cities, residential) ──────
// Weight: Damascus 40%, Aleppo 25%, Latakia 15%, Tartus 10%, Homs 10%
const WEIGHTS = { 'دمشق': 0.40, 'حلب': 0.25, 'اللاذقية': 0.15, 'طرطوس': 0.10, 'حمص': 0.10 };
const periods  = [...new Set(RESIDENTIAL_TREND.map(r => r.period))].sort();

export const COMPOSITE_INDEX = periods.map(period => {
  let weighted = 0;
  let totalWeight = 0;
  RESIDENTIAL_TREND.filter(r => r.period === period).forEach(r => {
    const w = WEIGHTS[r.city] ?? 0;
    weighted += r.avg_price_sqm * w;
    totalWeight += w;
  });
  const avg = totalWeight > 0 ? Math.round(weighted / totalWeight) : null;
  return { period, avg_price_sqm: avg };
});

